import React, { useState, useEffect } from 'react';
import { View, Text, TouchableOpacity, TextInput, Alert, StyleSheet } from 'react-native';
import ReactNativeBiometrics from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';
import CryptoJS from 'crypto-js';

const BIOMETRIC_KEY = 'biometric_public_key';
const SESSION_TOKEN_KEY = 'encrypted_session_token';
const BIOMETRIC_ENABLED_KEY = 'biometric_enabled';

const rnBiometrics = new ReactNativeBiometrics({ allowDeviceCredentials: true });

const generateSessionToken = () => {
  return CryptoJS.lib.WordArray.random(32).toString();
};

const encryptData = (data, key) => {
  return CryptoJS.AES.encrypt(data, key).toString();
};

const decryptData = (encryptedData, key) => {
  const bytes = CryptoJS.AES.decrypt(encryptedData, key);
  return bytes.toString(CryptoJS.enc.Utf8);
};

export const BiometricService = {
  checkBiometricAvailability: async () => {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      return { available, biometryType };
    } catch (error) {
      console.error('Biometric check error:', error);
      return { available: false, biometryType: null };
    }
  },

  setupBiometricAuth: async (sessionToken) => {
    try {
      const { publicKey } = await rnBiometrics.createKeys();
      await AsyncStorage.setItem(BIOMETRIC_KEY, publicKey);
      
      const payload = JSON.stringify({
        token: sessionToken,
        timestamp: Date.now()
      });
      
      const { success, signature } = await rnBiometrics.createSignature({
        promptMessage: 'Authenticate to enable biometric login',
        payload: payload
      });

      if (success) {
        const encryptedToken = encryptData(sessionToken, signature);
        await AsyncStorage.setItem(SESSION_TOKEN_KEY, encryptedToken);
        await AsyncStorage.setItem(BIOMETRIC_ENABLED_KEY, 'true');
        return { success: true, signature };
      }
      
      return { success: false };
    } catch (error) {
      console.error('Biometric setup error:', error);
      return { success: false, error };
    }
  },

  authenticateWithBiometrics: async () => {
    try {
      const publicKey = await AsyncStorage.getItem(BIOMETRIC_KEY);
      const encryptedToken = await AsyncStorage.getItem(SESSION_TOKEN_KEY);
      
      if (!publicKey || !encryptedToken) {
        return { success: false, error: 'Biometric not configured' };
      }

      const payload = JSON.stringify({
        action: 'authenticate',
        timestamp: Date.now()
      });

      const { success, signature } = await rnBiometrics.createSignature({
        promptMessage: 'Authenticate to access your account',
        payload: payload,
        cancelButtonText: 'Use Password'
      });

      if (success && signature) {
        try {
          const decryptedToken = decryptData(encryptedToken, signature);
          
          if (decryptedToken) {
            return { 
              success: true, 
              sessionToken: decryptedToken,
              signature 
            };
          }
        } catch (decryptError) {
          console.error('Decryption failed:', decryptError);
          return { success: false, error: 'Authentication failed' };
        }
      }

      return { success: false, error: 'Biometric authentication failed' };
    } catch (error) {
      console.error('Biometric auth error:', error);
      return { success: false, error: error.message };
    }
  },

  disableBiometricAuth: async () => {
    try {
      await rnBiometrics.deleteKeys();
      await AsyncStorage.multiRemove([
        BIOMETRIC_KEY,
        SESSION_TOKEN_KEY,
        BIOMETRIC_ENABLED_KEY
      ]);
      return { success: true };
    } catch (error) {
      console.error('Disable biometric error:', error);
      return { success: false, error };
    }
  },

  isBiometricEnabled: async () => {
    const enabled = await AsyncStorage.getItem(BIOMETRIC_ENABLED_KEY);
    return enabled === 'true';
  }
};

const LoginScreen = ({ navigation }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    checkBiometricAndAutoLogin();
  }, []);

  const checkBiometricAndAutoLogin = async () => {
    const { available, biometryType } = await BiometricService.checkBiometricAvailability();
    setBiometricAvailable(available);
    setBiometricType(biometryType);

    const isBiometricEnabled = await BiometricService.isBiometricEnabled();
    
    if (available && isBiometricEnabled) {
      handleBiometricLogin();
    }
  };

  const handleBiometricLogin = async () => {
    setLoading(true);
    const result = await BiometricService.authenticateWithBiometrics();
    
    if (result.success) {
      await validateAndNavigate(result.sessionToken, result.signature);
    } else {
      setLoading(false);
      if (result.error !== 'User cancellation') {
        Alert.alert('Authentication Failed', 'Please use password to login');
      }
    }
  };

  const validateAndNavigate = async (sessionToken, signature) => {
    const isValid = await validateSessionWithServer(sessionToken, signature);
    
    if (isValid) {
      navigation.replace('Home', { sessionToken, signature });
    } else {
      Alert.alert('Session Expired', 'Please login again');
      await BiometricService.disableBiometricAuth();
      setLoading(false);
    }
  };

  const validateSessionWithServer = async (sessionToken, signature) => {
    try {
      const response = await fetch('https://your-api.com/validate-session', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          sessionToken,
          signature,
          timestamp: Date.now()
        })
      });
      
      const data = await response.json();
      return data.valid === true;
    } catch (error) {
      console.error('Session validation error:', error);
      return false;
    }
  };

  const handlePasswordLogin = async () => {
    if (!username || !password) {
      Alert.alert('Error', 'Please enter username and password');
      return;
    }

    setLoading(true);

    try {
      const response = await fetch('https://your-api.com/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ username, password })
      });

      const data = await response.json();

      if (data.success && data.sessionToken) {
        if (biometricAvailable) {
          Alert.alert(
            'Enable Biometric Login',
            `Would you like to enable ${biometricType} for faster login?`,
            [
              {
                text: 'No',
                onPress: () => navigation.replace('Home', { sessionToken: data.sessionToken }),
                style: 'cancel'
              },
              {
                text: 'Yes',
                onPress: async () => {
                  const setupResult = await BiometricService.setupBiometricAuth(data.sessionToken);
                  if (setupResult.success) {
                    navigation.replace('Home', { 
                      sessionToken: data.sessionToken,
                      signature: setupResult.signature 
                    });
                  } else {
                    Alert.alert('Setup Failed', 'Biometric setup failed. You can enable it later in settings.');
                    navigation.replace('Home', { sessionToken: data.sessionToken });
                  }
                }
              }
            ]
          );
        } else {
          navigation.replace('Home', { sessionToken: data.sessionToken });
        }
      } else {
        Alert.alert('Login Failed', data.message || 'Invalid credentials');
      }
    } catch (error) {
      Alert.alert('Error', 'Network error. Please try again.');
      console.error('Login error:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>
      
      {biometricAvailable && (
        <TouchableOpacity 
          style={styles.biometricButton}
          onPress={handleBiometricLogin}
          disabled={loading}
        >
          <Text style={styles.biometricButtonText}>
            Login with {biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}
          </Text>
        </TouchableOpacity>
      )}

      <TextInput
        style={styles.input}
        placeholder="Username"
        value={username}
        onChangeText={setUsername}
        autoCapitalize="none"
      />

      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
      />

      <TouchableOpacity 
        style={styles.loginButton}
        onPress={handlePasswordLogin}
        disabled={loading}
      >
        <Text style={styles.loginButtonText}>
          {loading ? 'Loading...' : 'Login with Password'}
        </Text>
      </TouchableOpacity>
    </View>
  );
};

const HomeScreen = ({ route, navigation }) => {
  const { sessionToken, signature } = route.params || {};
  const [biometricEnabled, setBiometricEnabled] = useState(false);

  useEffect(() => {
    checkBiometricStatus();
  }, []);

  const checkBiometricStatus = async () => {
    const enabled = await BiometricService.isBiometricEnabled();
    setBiometricEnabled(enabled);
  };

  const handleDisableBiometric = async () => {
    Alert.alert(
      'Disable Biometric',
      'Are you sure you want to disable biometric authentication?',
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Disable',
          style: 'destructive',
          onPress: async () => {
            const result = await BiometricService.disableBiometricAuth();
            if (result.success) {
              setBiometricEnabled(false);
              Alert.alert('Success', 'Biometric authentication disabled');
            }
          }
        }
      ]
    );
  };

  const handleEnableBiometric = async () => {
    if (sessionToken) {
      const result = await BiometricService.setupBiometricAuth(sessionToken);
      if (result.success) {
        setBiometricEnabled(true);
        Alert.alert('Success', 'Biometric authentication enabled');
      } else {
        Alert.alert('Error', 'Failed to enable biometric authentication');
      }
    }
  };

  const handleLogout = async () => {
    await BiometricService.disableBiometricAuth();
    
    try {
      await fetch('https://your-api.com/logout', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ sessionToken })
      });
    } catch (error) {
      console.error('Logout error:', error);
    }

    navigation.replace('Login');
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome!</Text>
      <Text style={styles.subtitle}>Session Active</Text>
      
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Security Settings</Text>
        
        {biometricEnabled ? (
          <TouchableOpacity 
            style={styles.dangerButton}
            onPress={handleDisableBiometric}
          >
            <Text style={styles.buttonText}>Disable Biometric Login</Text>
          </TouchableOpacity>
        ) : (
          <TouchableOpacity 
            style={styles.primaryButton}
            onPress={handleEnableBiometric}
          >
            <Text style={styles.buttonText}>Enable Biometric Login</Text>
          </TouchableOpacity>
        )}
      </View>

      <TouchableOpacity 
        style={styles.logoutButton}
        onPress={handleLogout}
      >
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

